// @chirag127/astro-shell/family-data
// ─────────────────────────────────────────────────────────────────────
// Single dynamic registry for every entity in the chirag127/oriz family.
//
// Apps import + render from this module; never hardcode the list.
// See: knowledge/decisions/architecture/dynamic-family-data-registry.md
//
// REGENERATED by scripts/discover-family.mjs (daily GH Action cron).
// Manual edits survive until the next discovery diff. To force a refresh:
//   node scripts/discover-family.mjs
// ─────────────────────────────────────────────────────────────────────

/* ───── Types ─────────────────────────────────────────────────────── */

export type AppCategory = 'hub' | 'personal' | 'content' | 'tools'
export type AppStatus = 'live' | 'beta' | 'planned'

export interface FamilyApp {
  /** Repo slug, e.g. `oriz-pages-blog-app`. */
  slug: string
  /** Display name, e.g. `oriz / blog`. */
  name: string
  /** Canonical URL. */
  url: string
  category: AppCategory
  tagline?: string
  status: AppStatus
}

export type PackageCategory = 'astro' | 'auth' | 'oriz' | 'omni'

export interface FamilyPackage {
  /** Short slug, e.g. `astro-shell`. */
  slug: string
  /** Full npm name, e.g. `@chirag127/astro-shell`. */
  npm: string
  /** GitHub repo, e.g. `chirag127/astro-shell-npm-pkg`. */
  ghRepo: string
  category: PackageCategory
  version?: string
  tagline?: string
}

export type ApiCategory = 'finance' | 'health' | 'utility' | 'global'
export type ApiStatus = 'live' | 'planned'

export interface FamilyApi {
  slug: string
  /** Canonical subdomain URL. */
  url: string
  rapidApiUrl?: string
  /** Open-API schema URL (typically GH Pages). */
  schemaUrl?: string
  category: ApiCategory
  status: ApiStatus
  tagline?: string
}

export type BookChannel = 'amazon' | 'gumroad' | 'leanpub' | 'github' | 'web'
export type BookStatus = 'live' | 'beta' | 'planned'

export interface FamilyBook {
  slug: string
  title: string
  cover?: string
  channels: BookChannel[]
  price?: string
  status: BookStatus
  tagline?: string
}

export type ExtensionSurface = 'chrome' | 'firefox' | 'edge' | 'vscode' | 'mcp'

export interface FamilyExtension {
  slug: string
  surface: ExtensionSurface
  url: string
  tagline?: string
}

export interface FamilySkill {
  slug: string
  install: string
  description: string
}

