/* ───── Aggregate helpers ─────────────────────────────────────────── */

export interface FamilyDataSummary {
  apps: number
  packages: number
  apis: number
  books: number
  extensions: number
  skills: number
  total: number
}

export function familyDataSummary(): FamilyDataSummary {
  const apps = FAMILY_APPS.length
  const packages = FAMILY_PACKAGES.length
  const apis = FAMILY_APIS.length
  const books = FAMILY_BOOKS.length
  const extensions = FAMILY_EXTENSIONS.length
  const skills = FAMILY_SKILLS.length
  return {
    apps,
    packages,
    apis,
    books,
    extensions,
    skills,
    total: apps + packages + apis + books + extensions + skills,
  }
}
